const nowUtc = new Date();

// Get current UTC time components
const currentHour = nowUtc.getUTCHours();
const currentMinute = nowUtc.getUTCMinutes();
const currentSecond = nowUtc.getUTCSeconds();
const currentMs = nowUtc.getUTCMilliseconds();

// Total ms since midnight UTC
const elapsedToday =
  ((currentHour * 60 + currentMinute) * 60 + currentSecond) * 1000 + currentMs;

// Total ms in a day
const dayMs = 24 * 60 * 60 * 1000;

// Remaining time until next day
const waitMs = dayMs - elapsedToday;
const waitSeconds = Math.floor(waitMs / 1000);

return [
  {
    json: {
      now_utc: nowUtc.toISOString(),
      seconds_until_next_day: waitSeconds
    }
  }
];

