// Step 1: Get the raw JSON string from the first input item's 'text' field
const raw = $input.first().json.text;

// Step 2: Remove the ```json\n and ``` wrappers if they exist
const cleaned = raw.trim().replace(/^```json\n/, '').replace(/```$/, '');

// Step 3: Try to parse the cleaned JSON string
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (error) {
  throw new Error('Failed to parse JSON: ' + error.message);
}

// Step 4: Return the object as a single item, preserving all keys like subject1, body1, etc.
return [
  {
    json: parsed
  }
];

