const inputWebsite = $input.first().json.website;  // e.g., "https://chatgpt.com"

function removeProtocol(url) {
  return url.trim().replace(/^https?:\/\//i, '');
}

// Return cleaned result
return [
  {
    json: {
      original: inputWebsite,
      withoutProtocol: removeProtocol(inputWebsite),
    }
  }
];

const rawText = items[0].json.text;

// Extract JSON string from markdown code block
const jsonString = rawText.match(/```json\s*([\s\S]*?)\s*```/)?.[1];

if (!jsonString) {
  throw new Error("No valid JSON found in input text.");
}

// Parse the extracted JSON
const data = JSON.parse(jsonString);

// Utility function to encode arrays
const encodeArray = (arr) => encodeURIComponent(arr.join('; '));
const encodeArrayRaw = (arr) => arr.length > 0 ? `[]=${encodeArray(arr)}` : '[]=';

// Start building the URL
let baseUrl = "https://api.apollo.io/api/v1/mixed_people/search?";

const queryParams = [
  `person_titles${encodeArrayRaw(data.person_titles || [])}`,
  `include_similar_titles=${data.include_similar_titles}`,
  `q_keywords${encodeArrayRaw(data.q_keywords || [])}`,
  `person_locations${encodeArrayRaw(data.person_locations || [])}`,
  `person_seniorities${encodeArrayRaw(data.person_seniorities || [])}`,
  `organization_locations${encodeArrayRaw(data.organization_locations || [])}`,
  `q_organization_domains_list${encodeArrayRaw(data.q_organization_domains_list || [])}`,
  `contact_email_status${encodeArrayRaw(data.contact_email_status || [])}`,
  `organization_ids[]=${(data.organization_ids || []).join(',')}`,
  `organization_num_employees_ranges${encodeArrayRaw(data.organization_num_employees_ranges || [])}`,
  `revenue_range[min]=${data.revenue_range?.min ?? ''}`,
  `revenue_range[max]=${data.revenue_range?.max ?? ''}`,
  `currently_using_all_of_technology_uids${encodeArrayRaw(data.currently_using_all_of_technology_uids || [])}`,
  `currently_using_any_of_technology_uids${encodeArrayRaw(data.currently_using_any_of_technology_uids || [])}`,
  `currently_not_using_any_of_technology_uids${encodeArrayRaw(data.currently_not_using_any_of_technology_uids || [])}`,
  `q_organization_job_titles${encodeArrayRaw(data.q_organization_job_titles || [])}`,
  `organization_job_locations${encodeArrayRaw(data.organization_job_locations || [])}`,
  `organization_num_jobs_range[min]=${data.organization_num_jobs_range?.min ?? ''}`,
  `organization_num_jobs_range[max]=${data.organization_num_jobs_range?.max ?? ''}`,
  `page=${data.page ?? 1}`,
  `per_page=${data.per_page ?? 100}`,
  `organization_industries${encodeArrayRaw(data.organization_industries || [])}`,
  `person_job_functions${encodeArrayRaw(data.person_job_functions || [])}`
];

// Final URL
const finalUrl = baseUrl + queryParams.join('&');

return [
  {
    json: {
      url: finalUrl
    }
  }
];

const enrichmentResults = $input.first().json;
const matches = enrichmentResults.matches || [];

const enrichedPeople = matches.map(match => {
  const person = match.person || {};
  return {
    id: person.id,
    name: `${person.first_name || ''} ${person.last_name || ''}`.trim(),
    title: person.title,
    email: person.email,
    personal_emails: person.personal_emails || [],
    phone_numbers: person.phone_numbers || [],
    linkedin_url: person.linkedin_url,
    company: person.organization ? {
      name: person.organization.name,
      domain: person.organization.primary_domain,
      industry: person.organization.industry,
      employees: person.organization.estimated_num_employees
    } : null,
    location: person.city && person.state ? `${person.city}, ${person.state}` : (person.city || person.state || ''),
    enrichment_status: match.enrichment_status
  };
});

return enrichedPeople.map(person => ({ json: person }));
